const crypto = require('crypto');
const https = require('https');

const APP_KEY    = 'db98a65eba39bf6886faf56e9249589e';
const APP_SECRET = '3896fff8060522f365d380dc03db8a6d57c5fad6';

const row = $input.first().json;
const ACCESS_TOKEN = row.access_token;

let categories = row.categories;
if (typeof categories === 'string') {
  try { categories = JSON.parse(categories); } catch(e) { categories = []; }
}

if (!ACCESS_TOKEN) throw new Error('No access_token in config.temu_credentials');
if (!categories || !categories.length) throw new Error('No temu_ro categories in DB. Run sync-cats first.');

function buildSign(params) {
  const keys = Object.keys(params).sort();
  let s = APP_SECRET;
  for (const k of keys) s += k + String(params[k]);
  s += APP_SECRET;
  return crypto.createHash('md5').update(s).digest('hex').toUpperCase();
}

async function temuPost(type, reqBody = {}) {
  const timestamp = String(Math.floor(Date.now() / 1000));
  const sysParams = { type, app_key: APP_KEY, access_token: ACCESS_TOKEN, timestamp, data_type: 'JSON' };
  const sign = buildSign(sysParams);
  const qs = Object.entries({ ...sysParams, sign }).map(([k,v]) => `${k}=${encodeURIComponent(v)}`).join('&');
  const body = JSON.stringify(Object.keys(reqBody).length ? { request: reqBody } : {});

  return new Promise((resolve, reject) => {
    const opts = {
      hostname: 'openapi-b-eu.temu.com',
      path: `/openapi/router?${qs}`,
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(body) }
    };
    const req = https.request(opts, res => {
      let d = '';
      res.on('data', c => d += c);
      res.on('end', () => { try { resolve(JSON.parse(d)); } catch(e) { resolve({ raw: d }); } });
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
}

// Normalizeaza lista de caracteristici din raspunsul Temu
// la formatul asteptat de catalogs.sync_category_from_api()
function parseCharacteristics(result) {
  const list =
    result?.propertyList ||
    result?.property_list ||
    result?.templateList ||
    result?.specList ||
    [];

  return list.map(prop => {
    const values = (prop.valueList || prop.value_list || prop.vidList || []).map(v => ({
      id: String(v.vid || v.value_id || v.id),
      name: String(v.name || v.value_name || '')
    })).filter(v => v.id && v.name);

    // type_id: 1=text, 2=select, 3=number, 4=multiselect
    const inputType = prop.inputType || prop.input_type || prop.type || 1;
    let type_id = 1;
    if (inputType === 2 || inputType === 'single_select') type_id = 2;
    else if (inputType === 3 || inputType === 'number')        type_id = 3;
    else if (inputType === 4 || inputType === 'multi_select')  type_id = 4;

    return {
      id: String(prop.specId || prop.spec_id || prop.propertyId || prop.property_id),
      name: String(prop.name || prop.propertyName || prop.property_name || ''),
      is_mandatory: prop.required === true || prop.isMandatory === true || prop.is_mandatory === true || false,
      allows_custom: prop.allowsCustom === true || prop.allows_custom === true || false,
      type_id,
      values
    };
  }).filter(p => p.id && p.name);
}

// Procuram atributele pentru fiecare categorie, cu delay de 200ms intre requesturi
const results = [];
let errors = 0;

for (const cat of categories) {
  try {
    const resp = await temuPost('bg.local.goods.template.get', { catId: parseInt(cat.category_id) });

    if (!resp.success) {
      // Unele categorii pot sa nu aiba template (ex: categorii parinte gresite in sync)
      errors++;
      continue;
    }

    const characteristics = parseCharacteristics(resp.result);

    results.push({
      category_id: cat.category_id,
      category_name: cat.category_name,
      characteristics: JSON.stringify(characteristics)
    });
  } catch(e) {
    errors++;
  }

  // Delay 200ms intre requesturi pentru a evita rate limiting
  await new Promise(r => setTimeout(r, 200));
}

if (!results.length) {
  throw new Error(`No attributes fetched. Errors: ${errors}/${categories.length}`);
}

// Returnam un item per categorie — nodul Postgres urmator ruleaza de N ori
return results.map(r => ({ json: r }));

const results = $input.all().map(item => item.json.result);
const total = results.length;
const totalChars = results.reduce((s, r) => s + (r?.characteristics_count || 0), 0);
const totalVals  = results.reduce((s, r) => s + (r?.values_count || 0), 0);

return [{ json: {
  success: true,
  categories_synced: total,
  characteristics_synced: totalChars,
  values_synced: totalVals,
  marketplace: 'temu_ro'
} }];
